<div class="card h-100 product-card" @onclick="HandleCardClick" role="button">
    <div class="card-img-top bg-secondary d-flex align-items-center justify-content-center"
         style="height: 180px;"
         role="img"
         aria-label="@Product.Name">
        <span class="text-white text-center px-2">@Product.Name</span>
    </div>
    <div class="card-body d-flex flex-column">
        <h6 class="card-title mb-1">@Product.Name</h6>
        <p class="text-success fw-bold mb-1">@Product.Price.ToString("C")</p>
        <p class="mb-1" title="@($"{Product.Rating:F1} out of 5")">@GetStarRating(Product.Rating)</p>
        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2">Out of Stock</span>
        }
        <button class="btn btn-primary btn-sm mt-auto"
                disabled="@(!Product.InStock)"
                @onclick="HandleAddToCart"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private async Task HandleCardClick()
    {
        await OnProductSelected.InvokeAsync(Product);
    }

    private async Task HandleAddToCart()
    {
        if (Product.InStock)
        {
            await OnAddToCart.InvokeAsync(Product);
        }
    }

    private static string GetStarRating(double rating)
    {
        int fullStars = (int)Math.Round(rating);
        int emptyStars = 5 - fullStars;
        return new string('★', fullStars) + new string('☆', emptyStars);
    }
}
"}

{"path": "/tmp/sv-ffd9b820a2864245b71ccdea9d33ab81/Components/Pages/Catalog/CatalogFilters.razor", "file_text": "
<div class="p-3 border rounded bg-light">
    <h5 class="mb-3">Filters</h5>

    <div class="mb-3">
        <label class="form-label fw-bold">Categories</label>
        @if (Categories is not null)
        {
            @foreach (var category in Categories)
            {
                <div class="form-check">
                    <input class="form-check-input"
                           type="checkbox"
                           id="@($"cat-{category}")"
                           checked="@IsSelected(category)"
                           @onchange="@(e => ToggleCategory(category, (bool)e.Value!))" />
                    <label class="form-check-label" for="@($"cat-{category}")">@category</label>
                </div>
            }
        }
    </div>

    <div class="mb-3">
        <label class="form-label fw-bold">Price Range</label>
        <div class="d-flex gap-2 align-items-center">
            <input type="number"
                   class="form-control form-control-sm"
                   placeholder="Min"
                   value="@_minPrice"
                   @onchange="@(e => _minPrice = ParseDecimal(e.Value))" />
            <span>–</span>
            <input type="number"
                   class="form-control form-control-sm"
                   placeholder="Max"
                   value="@_maxPrice"
                   @onchange="@(e => _maxPrice = ParseDecimal(e.Value))" />
        </div>
    </div>

    <div class="form-check mb-3">
        <input class="form-check-input"
               type="checkbox"
               id="inStockOnly"
               @bind="_inStockOnly" />
        <label class="form-check-label" for="inStockOnly">In Stock Only</label>
    </div>

    <div class="d-grid gap-2">
        <button class="btn btn-primary btn-sm" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFilters">Clear Filters</button>
    </div>
</div>

@code {
    [Parameter]
    public List<string>? Categories { get; set; }

    [Parameter]
    public EventCallback<ProductFilter> OnApplyFilters { get; set; }

    private List<string> _selectedCategories = new();
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;

    private bool IsSelected(string category) => _selectedCategories.Contains(category);

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
        {
            if (!_selectedCategories.Contains(category))
                _selectedCategories.Add(category);
        }
        else
        {
            _selectedCategories.Remove(category);
        }
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            Categories: _selectedCategories.Count > 0 ? new List<string>(_selectedCategories) : null,
            MinPrice: _minPrice,
            MaxPrice: _maxPrice,
            InStockOnly: _inStockOnly
        );
        await OnApplyFilters.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        await OnApplyFilters.InvokeAsync(new ProductFilter(null, null, null, false));
    }

    private static decimal? ParseDecimal(object? value)
    {
        if (value is null || string.IsNullOrWhiteSpace(value.ToString()))
            return null;
        return decimal.TryParse(value.ToString(), out var result) ? result : null;
    }
}
"}

