<div class="d-flex justify-content-between align-items-center mb-3 flex-wrap gap-2">
    <div class="d-flex align-items-center gap-2">
        <label class="form-label mb-0 fw-bold" for="sortDropdown">Sort by:</label>
        <select id="sortDropdown"
                class="form-select form-select-sm"
                style="width: auto;"
                value="@SortBy"
                @onchange="HandleSortChange">
            <option value="price_asc">Price: Low to High</option>
            <option value="price_desc">Price: High to Low</option>
            <option value="name_asc">Name: A-Z</option>
            <option value="rating_desc">Rating: Highest</option>
        </select>
    </div>
    <span class="text-muted">
        Showing @Start–@End of @TotalCount products
    </span>
</div>

@code {
    [Parameter]
    public string SortBy { get; set; } = "price_asc";

    [Parameter]
    public int TotalCount { get; set; }

    [Parameter]
    public int Page { get; set; }

    [Parameter]
    public int PageSize { get; set; }

    [Parameter]
    public EventCallback<string> OnSortChanged { get; set; }

    private int Start => TotalCount == 0 ? 0 : (Page - 1) * PageSize + 1;
    private int End => Math.Min(Page * PageSize, TotalCount);

    private async Task HandleSortChange(ChangeEventArgs e)
    {
        await OnSortChanged.InvokeAsync(e.Value?.ToString() ?? "price_asc");
    }
}
